import React, { useMemo } from 'react';
import {
  View, Text, ScrollView, FlatList, StyleSheet, Image
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { useAppStore } from '../../store/useAppStore';
import F1HeroBanner from '../../components/tv/F1HeroBanner';
import TvFocusable from '../../components/tv/TvFocusable';
import TvMovieCard from '../../components/tv/TvMovieCard';
import TvWatchlistHeroBanner from '../../components/tv/TvWatchlistHeroBanner';
import { Film, Tv, Cpu, Trophy, Radio } from 'lucide-react-native';

// ─── Categorías ───────────────────────────────────────────────────────────────
const CATEGORIES = [
  { id: 'movies', label: 'Películas', screen: 'movie', icon: Film, accent: '#BF5AF2', bg: 'data:image/jpeg;base64,' },
  { id: 'series', label: 'Series', screen: 'series', icon: Tv, accent: '#FF375F', bg: 'data:image/jpeg;base64,' },
  { id: 'anime', label: 'Anime', screen: 'anime', icon: Cpu, accent: '#FFD60A', bg: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQFUJjlTXE9KbfLr8a--JaeJDd-gy4kE2ZcTA&s' },
  { id: 'sports', label: 'Deportes', screen: 'sport', icon: Trophy, accent: '#32D74B', bg: 'data:image/jpeg;base64,' },
  { id: 'channels', label: 'TV en Vivo', screen: 'tv', icon: Radio, accent: '#0A84FF', bg: 'https://images.unsplash.com/photo-1606814893907-59818b4dd428?q=80&w=800&auto=format&fit=crop' },
];

// ─── Category Button ──────────────────────────────────────────────────────────
const CategoryBtn = React.memo(function CategoryBtn({
  item,
  onPress,
}: {
  item: typeof CATEGORIES[0];
  onPress: () => void;
}) {
  const Icon = item.icon;
  return (
    <View style={{ marginRight: 24, marginVertical: 12 }}>
      <TvFocusable
        onPress={onPress}
        scaleTo={1.06}
        borderWidth={0}
        style={{ borderRadius: 12, width: 320, height: 140 }}
      >
        {(focused: boolean) => (
          <View style={[styles.categoryBtn, {
            borderColor: focused ? item.accent : 'rgba(255,255,255,0.05)',
            backgroundColor: '#0a0a0a',
            shadowColor: focused ? item.accent : 'transparent',
            shadowOpacity: focused ? 0.5 : 0,
            shadowRadius: 20,
            elevation: focused ? 10 : 0
          }]}>
            <Image
              source={{ uri: item.bg }}
              style={[StyleSheet.absoluteFillObject, { opacity: focused ? 0.6 : 0.3 }]}
              resizeMode="cover"
            />
            {/* Gradiente oscuro sobre la imagen para legibilidad */}
            <View style={[StyleSheet.absoluteFillObject, { backgroundColor: focused ? 'rgba(0,0,0,0.3)' : 'rgba(0,0,0,0.7)' }]} />

            <View style={styles.catContent}>
              <View style={[styles.iconBox, { backgroundColor: focused ? item.accent : 'rgba(255,255,255,0.1)' }]}>
                <Icon color={focused ? '#000' : '#fff'} size={24} />
              </View>
              <View style={{ flex: 1, paddingLeft: 16 }}>
                <Text style={[styles.categoryBtnText, { color: focused ? '#fff' : '#9ca3af' }]}>
                  {item.label}
                </Text>
                {focused && <Text style={{ color: item.accent, fontSize: 12, fontWeight: '700', marginTop: 4 }}>EXPLORAR</Text>}
              </View>
            </View>
          </View>
        )}
      </TvFocusable>
    </View>
  );
});

// ─── Content Row ──────────────────────────────────────────────────────────────
function ContentRow({ title, data, accent, onPress }: {
  title: string;
  data: any[];
  accent: string;
  onPress: (item: any) => void;
}) {
  if (!data || data.length === 0) return null;
  return (
    <View style={{ marginBottom: 40 }}>
      <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: 20, paddingLeft: 56 }}>
        <Text style={{ color: '#fff', fontSize: 22, fontWeight: '800', letterSpacing: 1 }}>{title}</Text>
        <View style={{ width: 6, height: 6, borderRadius: 3, backgroundColor: accent, marginLeft: 12 }} />
      </View>
      <FlatList
        horizontal
        showsHorizontalScrollIndicator={false}
        data={data}
        keyExtractor={(i) => i.id}
        contentContainerStyle={{ paddingHorizontal: 56, paddingBottom: 20 }}
        initialNumToRender={5}
        maxToRenderPerBatch={4}
        windowSize={5}
        renderItem={({ item }) => (
          <TvMovieCard
            item={item}
            onPress={() => onPress(item)}
            accentColor={accent}
            width={180}
            height={260}
          />
        )}
      />
    </View>
  );
}

// ─── Main Screen ──────────────────────────────────────────────────────────────
export default function TvDiscoverScreen({ currentTab }: { currentTab: string }) {
  const navigation = useNavigation<any>();
  const { cloudContent, watchHistory } = useAppStore();

  const trendingMovies = useMemo(
    () => cloudContent.filter((i) => i.type === 'movie').slice(0, 15),
    [cloudContent],
  );
  const trendingSeries = useMemo(
    () => cloudContent.filter((i) => i.type === 'series').slice(0, 15),
    [cloudContent],
  );
  const trendingAnime = useMemo(
    () => cloudContent.filter((i) => i.type === 'anime').slice(0, 15),
    [cloudContent],
  );

  const carouselData = useMemo(() => {
    // Si hay historial, tomamos los últimos 10 elementos.
    if (watchHistory && watchHistory.length > 0) {
      return watchHistory.slice(0, 10);
    }
    // Fallback: Si no tiene historial, sugerimos la más vista
    return trendingMovies.length > 0 ? [trendingMovies[0]] : [];
  }, [watchHistory, trendingMovies]);

  const handleCategoryPress = (item: typeof CATEGORIES[0]) => {
    if (item.screen === 'sport') {
      navigation.navigate('SportsTV');
    } else {
      navigation.navigate('LiveCategoryTV', { category: item.screen });
    }
  };

  const handleContentPress = (item: any) => {
    navigation.navigate('DetailTV', { item });
  };

  const handleWatchlistPress = (historyObj: any) => {
    const isHistoryObj = historyObj.item !== undefined;
    const contentItem = isHistoryObj ? historyObj.item : historyObj;
    navigation.navigate('DetailTV', { item: contentItem });
  };

  return (
    <ScrollView
      style={styles.container}
      contentContainerStyle={{ paddingTop: 80, paddingBottom: 100 }}
      showsVerticalScrollIndicator={false}
    >
      {/* 1. F1 HERO BANNER */}
      <View style={{ marginBottom: 48 }}>
        <F1HeroBanner onPress={() => navigation.navigate('F1TelemetryTV')} />
      </View>

      {/* 2. CATEGORÍAS */}
      <View style={{ marginBottom: 40 }}>
        <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: 16, paddingLeft: 56 }}>
          <Text style={{ color: '#fff', fontSize: 24, fontWeight: '900', letterSpacing: 1.5 }}>
            EXPLORAR
          </Text>
        </View>
        <FlatList
          horizontal
          showsHorizontalScrollIndicator={false}
          data={CATEGORIES}
          keyExtractor={(i) => i.id}
          contentContainerStyle={{ paddingHorizontal: 56 }}
          renderItem={({ item }) => (
            <CategoryBtn item={item} onPress={() => handleCategoryPress(item)} />
          )}
        />
      </View>

      {/* 3. HERO "SEGUIR VIENDO" (CARRUSEL) */}
      <View style={{ marginBottom: 56 }}>
        <FlatList
          horizontal
          showsHorizontalScrollIndicator={false}
          data={carouselData as any[]}
          keyExtractor={(i: any, idx) => i.timestamp ? `${i.item?.id}-${i.timestamp}` : `${i.id}-${idx}`}
          contentContainerStyle={{ paddingHorizontal: 56 }}
          initialNumToRender={3}
          renderItem={({ item }) => (
            <TvWatchlistHeroBanner
              historyData={item}
              onPress={() => handleWatchlistPress(item)}
            />
          )}
        />
      </View>

      {/* 4. FILAS DE CONTENIDO */}
      <ContentRow title="PELÍCULAS DESTACADAS" data={trendingMovies} accent="#BF5AF2" onPress={handleContentPress} />
      <ContentRow title="SERIES TOP" data={trendingSeries} accent="#FF375F" onPress={handleContentPress} />
      {trendingAnime.length > 0 && (
        <ContentRow title="ANIME DE TEMPORADA" data={trendingAnime} accent="#FFD60A" onPress={handleContentPress} />
      )}

    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#000', // Fondo negro puro cinematográfico
  },
  categoryBtn: {
    flex: 1,
    borderRadius: 12,
    borderWidth: 2,
    overflow: 'hidden',
  },
  catContent: {
    flex: 1,
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 20,
    zIndex: 10,
  },
  iconBox: {
    width: 48,
    height: 48,
    borderRadius: 24,
    alignItems: 'center',
    justifyContent: 'center',
  },
  categoryBtnText: {
    fontSize: 22,
    fontWeight: '800',
    letterSpacing: 1,
  },
});
